mapper.select:
SELECT c.COMPONENT_COMP_CD, c.COMPONENT_GOODS_CD, c.GOODS_CD, c.SALE_MEMBER_NO, m.COMPANY_NAME AS SELLER_NAME, c.STORAGE_TYPE_CD, st.DETAIL_CODE_NAME AS STORAGE_TYPE_NAME, c.PROCESS_DIV_CD, pt.DETAIL_CODE_NAME AS PROCESS_DIV_NAME, c.STOCK_UNIT_CD, ut.DETAIL_CODE_NAME AS STOCK_UNIT_NAME, c.SALE_DIV_CD, slt.DETAIL_CODE_NAME AS SALE_DIV_NAME, c.STDR_QTY, c.PO_HUB_PURC_CMPNY_CD, c.PO_HUB_PURC_SUPLR_DLV_PLC_CD, c.PO_HUB_PURC_SUPLR_CD, c.PO_HUB_PURC_UNIT_COST, c.PO_HUB_PURC_VAT_INCLD_YN, c.AUTO_VAT_CAL_YN, c.REG_ID, c.REG_DT, c.MOD_ID, c.MOD_DT FROM TB_COMPONENT_GOODS c LEFT JOIN TB_MEMBER m ON c.SALE_MEMBER_NO = m.MEMBER_NO LEFT JOIN TB_DETAIL_CODE st ON c.STORAGE_TYPE_CD = st.DETAIL_CODE AND st.GROUP_CODE = '001' AND st.CODE = '001001' LEFT JOIN TB_DETAIL_CODE pt ON c.PROCESS_DIV_CD = pt.DETAIL_CODE AND pt.GROUP_CODE = '001' AND pt.CODE = '001003' LEFT JOIN TB_DETAIL_CODE ut ON c.STOCK_UNIT_CD = ut.DETAIL_CODE AND ut.GROUP_CODE = '001' AND ut.CODE = '001004' LEFT JOIN TB_DETAIL_CODE slt ON c.SALE_DIV_CD = slt.DETAIL_CODE AND slt.GROUP_CODE = '007' AND slt.CODE = '007002'
ORDER BY c.REG_DT DESC
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

mapper.update:
UPDATE TB_COMPONENT_GOODS SET GOODS_CD = #{goodsCd}, STORAGE_TYPE_CD = #{storageTypeCd}, PROCESS_DIV_CD = #{processDivCd}, STOCK_UNIT_CD = #{stockUnitCd}, SALE_DIV_CD = #{saleDivCd}, STDR_QTY = #{stdrQty}, PO_HUB_PURC_CMPNY_CD = #{poHubPurcCmpnyCd}, PO_HUB_PURC_SUPLR_DLV_PLC_CD = #{poHubPurcSuplrDlvPlcCd}, PO_HUB_PURC_SUPLR_CD = #{poHubPurcSuplrCd}, PO_HUB_PURC_UNIT_COST = #{poHubPurcUnitCost}, PO_HUB_PURC_VAT_INCLD_YN = #{poHubPurcVatIncldYn}, AUTO_VAT_CAL_YN = #{autoVatCalYn}, MOD_ID = #{modId}, MOD_DT = NOW() WHERE COMPONENT_COMP_CD =
#{componentCompCd} #{productNo}
AND COMPONENT_GOODS_CD = #{componentGoodsCd}
